function groupAnagrams(strs) {
  const map = {};
  for (const s of strs) {
    const key = s.split('').sort().join('');
    if (!map[key]) map[key] = [];
    map[key].push(s);
  }
  return Object.values(map)
    .map(group => group.sort())
    .sort((a, b) => a[0].localeCompare(b[0]));
}
